import json

# Get NASDAQ Capital Market data - accessing directly from variable
nasdaq_stocks = locals()['var_functions.query_db:66']

# Create ticker-company mapping
ticker_to_company = {}
for stock in nasdaq_stocks:
    symbol = stock['Symbol']
    desc = stock['Company Description']
    company_name = desc.split('.')[0]
    ticker_to_company[symbol] = company_name

tickers = list(ticker_to_company.keys())
print('Total tickers to process:', len(tickers))

# Process first few tickers as a test
test_results = []
for i, ticker in enumerate(tickers[:3]):
    print(f'\nProcessing ticker {i+1}: {ticker}')
    try:
        # Query 2019 data
        query = f"SELECT High, Low FROM \"{ticker}\" WHERE Date >= '2019-01-01' AND Date <= '2019-12-31'"
        data = query_db('stocktrade_database', query)

        if data and len(data) > 0:
            volatile_days = 0
            for row in data:
                high_val = float(row['High'])
                low_val = float(row['Low'])
                if low_val > 0 and (high_val - low_val) > (0.2 * low_val):
                    volatile_days += 1

            test_results.append({
                'ticker': ticker,
                'company': ticker_to_company[ticker],
                'volatile_days': volatile_days,
                'total_days': len(data)
            })
        else:
            test_results.append({ticker: 'no data'})
    except Exception as e:
        test_results.append({ticker: f'error: {str(e)}'})

result = {'test_results': test_results}
print('__RESULT__:')
print(json.dumps(result))

